var chunk = (arr,size) => arr.reduce((a,_,i) => i%size==0 ? [...a,arr.slice(i,i+size)] : a,[]);

class Point extends Array {
  constructor(x,y,node) {
    super(2);
    this[0] = +x;
    this[1] = +y;
    this.node = node;
    node.pins.push(this);
    this.component = null;
    this.type = 'dual';
    this.state = 0;
    this.driving = false;
  }

  queue(state,drive) {
    updateQueue.push([this,state,drive]);
  }

  update(state,drive) {
    if (typeof drive === 'undefined') {
      this.driving = state !== null && this.type !== 'input';
    } else {
      this.driving = drive;
    }
    this.state = state;
    this.node.update(this);
  }

  get x() {return this[0]}
  get y() {return this[1]}
  set x(x) {this[0] = x}
  set y(y) {this[1] = y}
}

class Component {
  constructor(type,pins,rects) {
    this.type = type ?? '';
    this.pins = pins ?? [];
    this.rects = rects ?? [];
    this.pins.forEach(pin => pin.component = this);
  }

  draw(ctx) {
    this.rects.forEach(r => {
      ctx.fillRect(r[0][0],r[0][1],r[1][0]-r[0][0]+1,r[1][1]-r[0][1]+1);
    })
  }
}

class Transistor extends Component {
  constructor(pins,rects) {
    super('transistor',pins,rects);
    this.gate = pins[1];
    if (pins[0].y === pins[2].y) {
      this.source = pins[0].x > pins[2].x ? pins[0] : pins[2];
      this.drain = pins[0].x > pins[2].x ? pins[2] : pins[0];
    } else {
      this.source = pins[0].y > pins[2].y ? pins[0] : pins[2];
      this.drain = pins[0].y > pins[2].y ? pins[2] : pins[0];
    }
    this.pins.forEach(pin => pin.type = 'input');
    this.closed = false;
  }

  getOtherPin(pin) {
    if (!this.closed) return null;
    if (pin === this.source) return this.drain;
    if (pin === this.drain) return this.source;
    return null;
  }

  draw(ctx) {
    var r = this.rects[1];
    ctx.fillStyle = this.gate.node.color;
    ctx.fillRect(r[0][0],r[0][1],r[1][0]-r[0][0]+1,r[1][1]-r[0][1]+1);
    var r = this.rects[3];
    ctx.fillStyle = this.source.node.color;
    ctx.fillRect(r[0][0],r[0][1],r[1][0]-r[0][0]+1,r[1][1]-r[0][1]+1);
    var r = this.rects[2];
    ctx.fillStyle = this.drain.node.color;
    ctx.fillRect(r[0][0],r[0][1],r[1][0]-r[0][0]+1,r[1][1]-r[0][1]+1);
    var r = this.rects[0];
    var grad;
    if (this.pins[0].y === this.pins[2].y) {
      grad = ctx.createLinearGradient(r[1][0],r[0][1],r[0][0],r[0][1]);
      grad.addColorStop(1,this.drain.node.color);
      grad.addColorStop(0,this.source.node.color);
    } else {
      grad = ctx.createLinearGradient(r[0][0],r[1][1],r[0][0],r[0][1]);
      grad.addColorStop(1,this.drain.node.color);
      grad.addColorStop(0,this.source.node.color);
    }
    ctx.fillStyle = grad;
    ctx.fillRect(r[0][0],r[0][1],r[1][0]-r[0][0]+1,r[1][1]-r[0][1]+1);
  }

  update() {
    var pg = this.gate;
    var pa = this.source;
    var pb = this.drain;
    var sg = pg.state ?? pg.node.lastState;
    var sa = pa.state;
    var sb = pb.state;
    var state = pa.node.isDriven ? sa : pb.node.isDriven ? sb : null;
    this.closed = !sg && sg !== null;
    pa.queue(state);
    pb.queue(state);
  }
}

class VSS extends Component {
  constructor(pins,rects) {
    super('vss',pins,rects);
    this.out = pins[0];
    this.out.type = 'output';
  }

  draw(ctx) {
    ctx.fillStyle = '#6600FF';
    super.draw(ctx);
  }

  update() {}
}

class VDD extends Component {
  constructor(pins,rects) {
    super('vdd',pins,rects);
    this.out = pins[0];
    this.out.type = 'output';
  }

  draw(ctx) {
    ctx.fillStyle = '#66FF66';
    super.draw(ctx);
  }

  update() {}
}

class Resistor extends Component {
  constructor(pins,rects) {
    super('resistor',pins,rects);
    this.out = pins[0];
    this.out.type = 'output';
  }

  draw(ctx) {
    var r = this.rects[0];
      var grad = ctx.createLinearGradient(r[0][0],r[1][1],r[0][0],r[0][1]);
      grad.addColorStop(0,this.out.node.color);
      grad.addColorStop(1,vdd.out.node.color);
      ctx.fillStyle = grad;

    ctx.fillRect(r[0][0],r[0][1],r[1][0]-r[0][0]+1,r[1][1]-r[0][1]+1);
    ctx.fillStyle = vdd.out.node.color;
    this.rects.slice(1).forEach(r => {
      ctx.fillRect(r[0][0],r[0][1],r[1][0]-r[0][0]+1,r[1][1]-r[0][1]+1);
    })
  }

  update() {
    this.out.queue(vdd.out.node.state,false);
  }
}

class Input extends Component {
  constructor(pins,rects) {
    super('input',pins,rects);
    this.out = pins[0];
    this.out.type = 'output';
    this.state = 0;
  }

  draw(ctx) {
    ctx.fillStyle = this.state === null ? '#808080' : this.state ? '#6600FF' : '#66FF66';
    super.draw(ctx);
  }

  toggle() {
    this.state = 1 - this.state;
    this.out.update(this.state);
    if (this === vdd) components.filter(c => c.type === 'resistor').forEach(c => c.out.queue(this.state,false));
    stabilize();
    draw();
  }

  update() {
    this.out.queue(this.state);
  }
}

class Output extends Component {
  constructor(pins,rects) {
    super('output',pins,rects);
    this.in = pins[0];
    this.in.type = 'input';
    this.state = null;
  }

  draw(ctx) {
    ctx.fillStyle = this.in.node.color;
    super.draw(ctx);
  }

  update() {}
}

Component.transistor = Transistor;
Component.resistor = Resistor;
Component.vss = Output;
Component.vdd = Output;
Component.input = Input;
Component.output = Output;




